// scripts/seed_forests.ts
// ─────────────────────────────────────────────────────────────────
// Korea Trekking Hub — 자연휴양림 시드 + 카카오 지오코딩
// 실행: npx tsx scripts/seed_forests.ts
//
// 필요 환경변수 (.env.local):
//   NEXT_PUBLIC_SUPABASE_URL          Supabase 프로젝트 URL
//   SUPABASE_SERVICE_ROLE_KEY         서비스 롤 키 (RLS bypass)
//   KAKAO_REST_API_KEY                카카오 REST API 키 (지오코딩용)
//
// 동작:
//   1) 185개 휴양림을 카카오 로컬 API로 지오코딩 (키워드 → 주소 fallback)
//   2) 좌표를 채워 Supabase forests 테이블에 upsert
//   3) 지오코딩 실패 건은 geocoded=false 로 적재 (지도에서 자동 제외)
//   4) 결과를 scripts/forests_geocoded.json 으로도 저장 (재현/검수용)
//
// 카카오 키워드 검색 일 30,000건 무료. 185건이라 1회 실행으로 충분.
// 재실행 시 이미 좌표가 있는 항목은 캐시(json)에서 재사용해 호출을 아낍니다.
// ─────────────────────────────────────────────────────────────────
import { createClient } from '@supabase/supabase-js';
import fs from 'node:fs';
import path from 'node:path';

const SUPABASE_URL = process.env.NEXT_PUBLIC_SUPABASE_URL!;
const SERVICE_KEY  = process.env.SUPABASE_SERVICE_ROLE_KEY!;
const KAKAO_KEY    = process.env.KAKAO_REST_API_KEY!;

if (!SUPABASE_URL || !SERVICE_KEY) {
  console.error('❌ NEXT_PUBLIC_SUPABASE_URL / SUPABASE_SERVICE_ROLE_KEY 가 필요합니다.');
  process.exit(1);
}
if (!KAKAO_KEY) {
  console.warn('⚠️  KAKAO_REST_API_KEY 가 없습니다. 좌표 없이 적재만 진행합니다 (지도 미표시).');
}

const supabase = createClient(SUPABASE_URL, SERVICE_KEY);

interface ForestSeed {
  id: string; name: string; category: '국립' | '공립' | '사립';
  region: string; sigungu: string; address: string;
  lat: number | null; lng: number | null; geocoded: boolean;
  has_room: boolean; has_camp: boolean; has_waitlist: boolean;
  fcfs_type: string; open_time: string;
  lottery_targets: string[]; priority_targets: string[];
  reservation_url: string; reservation_org: string; note: string;
}

