// ── 카카오 로컬 API 지오코딩 ────────────────────────────────────────
const CACHE_PATH = path.join(process.cwd(), 'scripts', 'forests_geocoded.json');

async function kakaoKeyword(query: string): Promise<{ lat: number; lng: number } | null> {
  const url = `https://dapi.kakao.com/v2/local/search/keyword.json?query=${encodeURIComponent(query)}&size=1`;
  const res = await fetch(url, { headers: { Authorization: `KakaoAK ${KAKAO_KEY}` } });
  if (!res.ok) return null;
  const json = await res.json();
  const doc = json.documents?.[0];
  if (!doc) return null;
  // 카카오: x=경도(lng), y=위도(lat)
  return { lat: parseFloat(doc.y), lng: parseFloat(doc.x) };
}

async function kakaoAddress(query: string): Promise<{ lat: number; lng: number } | null> {
  const url = `https://dapi.kakao.com/v2/local/search/address.json?query=${encodeURIComponent(query)}&size=1`;
  const res = await fetch(url, { headers: { Authorization: `KakaoAK ${KAKAO_KEY}` } });
  if (!res.ok) return null;
  const json = await res.json();
  const doc = json.documents?.[0];
  if (!doc) return null;
  return { lat: parseFloat(doc.y), lng: parseFloat(doc.x) };
}

async function geocode(f: ForestSeed): Promise<{ lat: number; lng: number } | null> {
  // 1순위: 휴양림명 키워드 (가장 정확)  2순위: 시군 + 이름  3순위: 시군 주소
  const tries = [f.name, `${f.sigungu} ${f.name}`, f.address];
  for (const q of tries) {
    const hit = await kakaoKeyword(q);
    if (hit) return hit;
    await sleep(120); // rate-limit 여유
  }
  const addr = await kakaoAddress(f.sigungu);
  return addr;
}

const sleep = (ms: number) => new Promise((r) => setTimeout(r, ms));

async function run() {
  // 캐시 로드 (재실행 시 호출 절약)
  let cache: Record<string, { lat: number; lng: number }> = {};
  if (fs.existsSync(CACHE_PATH)) {
    try { cache = JSON.parse(fs.readFileSync(CACHE_PATH, 'utf8')); } catch {}
  }

  let ok = 0, fail = 0, cached = 0;
  for (const f of FORESTS) {
    if (cache[f.id]) {
      f.lat = cache[f.id].lat; f.lng = cache[f.id].lng; f.geocoded = true; cached++;
      continue;
    }
    if (!KAKAO_KEY) { fail++; continue; }
    const hit = await geocode(f);
    if (hit) {
      f.lat = hit.lat; f.lng = hit.lng; f.geocoded = true;
      cache[f.id] = hit; ok++;
      process.stdout.write(`✅ ${f.name} (${hit.lat.toFixed(4)}, ${hit.lng.toFixed(4)})\n`);
    } else {
      f.geocoded = false; fail++;
      process.stdout.write(`⚠️  좌표 실패: ${f.name} [${f.sigungu}]\n`);
    }
    await sleep(120);
  }

  // 캐시 저장
  fs.writeFileSync(CACHE_PATH, JSON.stringify(cache, null, 1), 'utf8');
  console.log(`\n📍 지오코딩 결과 — 신규 ${ok} / 캐시 ${cached} / 실패 ${fail}`);

  // Supabase upsert (배치)
  console.log('🌱 forests 테이블 적재 중...');
  const chunkSize = 100;
  for (let i = 0; i < FORESTS.length; i += chunkSize) {
    const chunk = FORESTS.slice(i, i + chunkSize);
    const { error } = await supabase.from('forests').upsert(chunk, { onConflict: 'id' });
    if (error) { console.error('❌ upsert 실패:', error.message); process.exit(1); }
  }
  console.log(`✅ ${FORESTS.length}개 휴양림 적재 완료`);
  console.log(`   지도 표시 가능(좌표 보유): ${FORESTS.filter((f) => f.geocoded).length}개`);
  console.log('🎉 시드 완료!');
}

run();
